import React, { useState } from "react";

const STRIP_IMG = "data:image/png;base64,";

const ROLES = [
  {
    key: "jugador",
    tag: "Rol 01",
    name: "Jugador",
    desc: "Equipo, partidos y estadísticas.",
    sub: "Consulta tu equipo, próximos partidos y estadísticas personales.",
    color: "#7f77dd",
    hero: "data:image/png;base64,",
  },
  {
    key: "arbitro",
    tag: "Rol 02",
    name: "Árbitro",
    desc: "Marcador, tiempo y sanciones en vivo.",
    sub: "Controla el marcador, el tiempo y las sanciones durante los partidos en vivo.",
    color: "#e24b4a",
    hero: "data:image/png;base64,",
  },
  {
    key: "organizador",
    tag: "Rol 03",
    name: "Organizador",
    desc: "Equipos, calendario y configuración.",
    sub: "Gestiona equipos, calendario y configuración general del torneo.",
    color: "#3fc8ff",
    hero: "data:image/png;base64,",
  },
];

const N = ROLES.length;
const STEP = 100 / N;

const DEFAULT_STATE = {
  eyebrow: "Escuela Colombiana de Ingeniería Julio Garavito",
  sub: "Pasa el mouse sobre un rol para verlo aquí, y haz clic para elegirlo.",
};

export default function TechCupRoleSelector({ onContinue } = {}) {
  const [hovered, setHovered] = useState(null);
  const [selected, setSelected] = useState(null);

  const active = hovered || selected;
  const activeRole = ROLES.find((r) => r.key === active) || null;

  const handleContinue = () => {
    if (!selected) return;
    if (typeof onContinue === "function") {
      onContinue(selected);
    } else {
      window.location.href = `/login?rol=${selected}`;
    }
  };

  return (
    <div className="tc-wrap">
      <style>{`
        .tc-wrap{
          --tc-gold:#e8bd5f;
          width:100%;
          max-width:1000px;
          margin:0 auto;
          font-family:'Inter',sans-serif;
          color:#fff;
          box-sizing:border-box;
        }
        .tc-wrap *{ box-sizing:border-box; }
        .tc-stage-outer{
          background:radial-gradient(ellipse at 50% 0%, #241a3b 0%, #0f0a1a 60%);
          padding:50px 20px;
          border-radius:20px;
        }

        /* ---------- HERO ---------- */
        .tc-hero{
          position:relative;
          height:360px;
          border-radius:16px;
          overflow:hidden;
          margin-bottom:22px;
          background:#100a1e;
          border:1px solid rgba(255,255,255,0.12);
          display:flex;
          align-items:center;
        }
        .tc-hero-glow{ display:none; }
        .tc-hero-text{
          position:relative;
          z-index:2;
          padding:0 40px;
          max-width:52%;
        }
        .tc-hero-eyebrow{
          font-size:11px;
          letter-spacing:.22em;
          text-transform:uppercase;
          color:#9a8fc2;
          margin:0 0 10px;
        }
        .tc-hero-title{
          font-family:'Barlow Condensed',sans-serif;
          font-weight:800;
          font-size:clamp(32px,4.6vw,50px);
          margin:0 0 10px;
          letter-spacing:.01em;
          line-height:1;
        }
        .tc-hero-title span{ color:var(--tc-gold); }
        .tc-hero-sub{
          font-size:14.5px;
          color:rgba(255,255,255,0.68);
          line-height:1.6;
          margin:0;
          max-width:340px;
        }
        .tc-hero-imgs{
          position:absolute;
          inset:0;
          overflow:hidden;
          display:flex;
          align-items:flex-end;
          justify-content:flex-end;
          padding:16px 4% 0;
          pointer-events:none;
        }
        .tc-hero-img{
          position:absolute;
          bottom:0;
          right:4%;
          max-height:96%;
          max-width:48%;
          width:auto;
          height:auto;
          object-fit:contain;
          opacity:0;
          transform:translateY(18px);
          transition:opacity .45s ease, transform .5s cubic-bezier(.2,.8,.2,1);
          filter:drop-shadow(0 20px 30px rgba(0,0,0,0.5));
        }
        .tc-hero-img.active{ opacity:1; transform:translateY(0); }

        @media (max-width:640px){
          .tc-hero{ height:300px; }
          .tc-hero-text{ max-width:100%; padding:0 20px; }
          .tc-hero-img{ max-width:60%; max-height:88%; }
        }

        /* ---------- STRIP SELECTOR ---------- */
        .tc-stage{
          position:relative;
          width:100%;
          aspect-ratio:900/669;
          border-radius:16px;
          overflow:hidden;
          background:rgba(255,255,255,0.04);
          border:1px solid rgba(255,255,255,0.12);
        }
        .tc-base{
          position:absolute;
          inset:0;
          width:100%;
          height:100%;
          object-fit:cover;
          filter:grayscale(65%) brightness(.5) saturate(.7);
          transition:filter .45s ease;
        }
        .tc-zones{
          position:absolute;
          inset:0;
          display:flex;
        }
        .tc-zone{
          position:relative;
          flex:1 1 ${100 / N}%;
          height:100%;
          overflow:hidden;
          cursor:pointer;
          border:none;
          padding:0;
          background:transparent;
          -webkit-tap-highlight-color:transparent;
          transition:transform .4s cubic-bezier(.2,.8,.2,1);
          transform-origin:center bottom;
        }
        .tc-zone:hover, .tc-zone:focus-visible{ transform:scale(1.035); z-index:2; }

        .tc-spot{
          position:absolute;
          top:0; left:0;
          width:${N * 100}%;
          height:100%;
          background-image:url("${STRIP_IMG}");
          background-repeat:no-repeat;
          background-size:100% 100%;
          opacity:0;
          transition:opacity .45s ease;
          pointer-events:none;
        }
        .tc-zone:hover .tc-spot, .tc-zone:focus-visible .tc-spot, .tc-zone.selected .tc-spot{ opacity:1; }

        .tc-light{
          position:absolute;
          left:50%;
          bottom:0;
          width:130%;
          height:55%;
          transform:translateX(-50%);
          border-radius:50%;
          filter:blur(30px);
          opacity:0;
          transition:opacity .45s ease;
          pointer-events:none;
        }
        .tc-zone:hover .tc-light, .tc-zone:focus-visible .tc-light, .tc-zone.selected .tc-light{ opacity:.55; }

        .tc-content{
          position:absolute;
          inset:0;
          display:flex;
          flex-direction:column;
          justify-content:space-between;
          padding:16px;
          pointer-events:none;
        }
        .tc-top-row{ display:flex; align-items:center; justify-content:space-between; }
        .tc-tag{
          font-family:'Barlow Condensed',sans-serif;
          font-size:11px;
          letter-spacing:.16em;
          text-transform:uppercase;
          color:rgba(255,255,255,0.6);
          opacity:0;
          transition:opacity .35s ease;
        }
        .tc-zone:hover .tc-tag, .tc-zone:focus-visible .tc-tag, .tc-zone.selected .tc-tag{ opacity:1; }
        .tc-dot{
          width:8px;height:8px;border-radius:50%;
          border:1.5px solid rgba(255,255,255,0.45);
          transition:background .3s ease, border-color .3s ease, box-shadow .3s ease;
          flex-shrink:0;
        }

        .tc-panel{
          position:relative;
          background:rgba(255,255,255,0.07);
          border:1px solid rgba(255,255,255,0.18);
          backdrop-filter:blur(14px);
          -webkit-backdrop-filter:blur(14px);
          border-radius:10px;
          padding:10px 12px;
          transform:translateY(14px);
          opacity:0;
          transition:transform .4s cubic-bezier(.2,.8,.2,1), opacity .4s ease;
        }
        .tc-zone:hover .tc-panel, .tc-zone:focus-visible .tc-panel, .tc-zone.selected .tc-panel{ transform:translateY(0); opacity:1; }
        .tc-role-name{
          font-family:'Barlow Condensed',sans-serif;
          font-weight:700;
          font-size:18px;
          text-transform:uppercase;
          letter-spacing:.02em;
          margin:0 0 2px;
        }
        .tc-role-desc{
          font-size:11px;
          line-height:1.4;
          color:rgba(255,255,255,0.68);
          margin:0;
        }

        .tc-footer{ display:flex; justify-content:center; margin-top:28px; }
        .tc-continue{
          font-family:'Barlow Condensed',sans-serif;
          font-weight:700;
          font-size:15px;
          letter-spacing:.08em;
          text-transform:uppercase;
          padding:13px 40px;
          background:var(--tc-gold);
          color:#1a1230;
          border:none;
          border-radius:6px;
          cursor:pointer;
          opacity:.35;
          pointer-events:none;
          transition:opacity .2s ease, transform .2s ease;
        }
        .tc-continue.ready{ opacity:1; pointer-events:auto; }
        .tc-continue.ready:hover{ transform:translateY(-2px); }
      `}</style>

      <div className="tc-stage-outer">
        <div className="tc-hero">
          <span
            className="tc-hero-glow"
            style={{
              background: `radial-gradient(circle, ${activeRole ? activeRole.color : "#e8bd5f"}, transparent 70%)`,
            }}
          />
          <div className="tc-hero-text">
            <p className="tc-hero-eyebrow">
              {activeRole ? "Rol seleccionado" : DEFAULT_STATE.eyebrow}
            </p>
            <h1 className="tc-hero-title">
              {activeRole ? (
                activeRole.name
              ) : (
                <>
                  TECH<span>CUP</span>
                </>
              )}
            </h1>
            <p className="tc-hero-sub">
              {activeRole ? activeRole.sub : DEFAULT_STATE.sub}
            </p>
          </div>
          {active === "arbitro" && (
            <video
              className="absolute inset-0 w-full h-full object-cover"
              src="/videos/video-arbitro.mp4"
              autoPlay
              muted
              loop
              playsInline
              style={{ filter: 'brightness(0.5)' }}
            />
          )}
          <div className="tc-hero-imgs">
            {ROLES.map((r) => (
              r.key !== "arbitro" && (
                <img
                  key={r.key}
                  className={`tc-hero-img${active === r.key ? " active" : ""}`}
                  src={r.hero}
                  alt={r.name}
                />
              )
            ))}
          </div>
        </div>

        <div className="tc-stage">
          <img className="tc-base" src={STRIP_IMG} alt="Roles TechCup" />
          <div className="tc-zones">
            {ROLES.map((r, i) => (
              <button
                key={r.key}
                type="button"
                className={`tc-zone${selected === r.key ? " selected" : ""}`}
                aria-label={r.name}
                onMouseEnter={() => setHovered(r.key)}
                onMouseLeave={() => setHovered(null)}
                onFocus={() => setHovered(r.key)}
                onBlur={() => setHovered(null)}
                onClick={() => { setSelected(r.key); if (typeof onContinue === "function") onContinue(r.key); }}
              >
                <span
                  className="tc-spot"
                  style={{ transform: `translateX(-${i * STEP}%)` }}
                />
                <span
                  className="tc-light"
                  style={{
                    background: `radial-gradient(ellipse, ${r.color}, transparent 70%)`,
                  }}
                />
                <div className="tc-content">
                  <div className="tc-top-row">
                    <span className="tc-tag">{r.tag}</span>
                    <span
                      className="tc-dot"
                      style={
                        active === r.key
                          ? {
                              background: r.color,
                              borderColor: r.color,
                              boxShadow: `0 0 8px ${r.color}`,
                            }
                          : undefined
                      }
                    />
                  </div>
                  <div
                    className="tc-panel"
                    style={{ borderColor: `${r.color}66` }}
                  >
                    <p className="tc-role-name">{r.name}</p>
                    <p className="tc-role-desc">{r.desc}</p>
                  </div>
                </div>
              </button>
            ))}
          </div>
        </div>


      </div>
    </div>
  );
}
